// Pega o texto da IA
let text = ($input.item.json.messages || $input.item.json.output || $input.item.json.text || "").toString();

// 1. MODO SILENCIOSO
if (text.includes("[SILENCIO]") || text.trim() === "") {
  return []; 
}

// 2. FILTRO DE ERRO DE LEITURA (A IA Vision falha, então assumimos sucesso manual)
if (text.includes("Não consegui ler") || text.includes("envie o PDF")) {
   // Força a mensagem de sucesso para acalmar o cliente
   text = "Recebi sua documentação e já anexei ao seu processo seguro. A equipe de auditoria vai analisar manualmente.";
}

// 3. SEPARADOR INTELIGENTE
// Se a mensagem for longa e não tiver "||" (Script de encerramento), mandamos como está.
// Se tiver "||", separamos.
let parts = text.includes("||") ? text.split("||") : [text];

// Limite de segurança: 4 balões
parts = parts.slice(0, 4);

const results = [];
const uniqueMessages = new Set(); 

for (const part of parts) {
  let cleanPart = part.trim();
  // Deduplicação: Se a frase for igual a anterior, ignora.
  if (cleanPart !== "" && !uniqueMessages.has(cleanPart)) {
    uniqueMessages.add(cleanPart);
    results.push({
      json: {
        message_part: cleanPart
      }
    });
  }
}

return results;
